import{_ as n,o as s,c as t,a4 as e}from"./chunks/framework.BDOgl-CJ.js";const g=JSON.parse('{"title":"🧱 AI 最简地基 · 写给只有高中数学的你","description":"","frontmatter":{},"headers":[],"relativePath":"ai-foundation-plain.md","filePath":"ai-foundation-plain.md","lastUpdated":1779702003000}'),o={name:"ai-foundation-plain.md"};function p(r,a,i,l,d,h){return s(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="🧱-ai-最简地基-·-写给只有高中数学的你" tabindex="-1">🧱 AI 最简地基 · 写给只有高中数学的你 <a class="header-anchor" href="#🧱-ai-最简地基-·-写给只有高中数学的你" aria-label="Permalink to &quot;🧱 AI 最简地基 · 写给只有高中数学的你&quot;">​</a></h1><blockquote><p>不要公式，只要直觉。每章一个问题，一段话，一个比喻。</p></blockquote><hr><h2 id="_1-什么是向量" tabindex="-1">1. 什么是向量 <a class="header-anchor" href="#_1-什么是向量" aria-label="Permalink to &quot;1. 什么是向量&quot;">​</a></h2><p><strong>问题：怎么用数字描述一个东西？</strong></p><p>你描述一个人：「身高 175，体重 70」。</p><p>写成 <code>[175, 70]</code>，这就是向量。AI 里每个词、每张图、每句话都被表示成这样的数字串，叫 Embedding。</p><p><strong>比喻</strong>：向量就是东西的「身份证号」。你不需要看懂号码，只需要知道相似的号码 = 相似的东西。</p><hr><h2 id="_2-什么是点积" tabindex="-1">2. 什么是点积 <a class="header-anchor" href="#_2-什么是点积" aria-label="Permalink to &quot;2. 什么是点积&quot;">​</a></h2><p><strong>问题：两个东西有多像？</strong></p><p><code>[175, 70]</code> 和 <code>[180, 75]</code> 很像。<code>[175, 70]</code> 和 <code>[60, 5]</code> 完全不像。</p><p>点积 = 一个数学操作，算「像不像」。数字越大越像，0 表示无关，负数表示相反。</p><p><strong>比喻</strong>：点积就是「好感度测试仪」。把两个人的兴趣标签对一遍，匹配的越多分值越高。</p><hr><h2 id="_3-什么是-softmax" tabindex="-1">3. 什么是 softmax <a class="header-anchor" href="#_3-什么是-softmax" aria-label="Permalink to &quot;3. 什么是 softmax&quot;">​</a></h2><p><strong>问题：怎么把一堆分数变成百分比？</strong></p><p>原始分：[10, 5, 1] → 处理后：[0.70, 0.28, 0.02]</p><p>三个步骤：① 用 e^x 把所有人变正数 ② 全部加起来 ③ 每人除以总和。</p><p>处理完加起来一定 = 1（= 100%）。谁分高谁占大头。</p><p><strong>比喻</strong>：三个人分蛋糕。不是平均分，是按「谁更饿」分。越饿的拿越大块，但蛋糕永远是一整个。</p><hr><h2 id="_4-什么是-attention" tabindex="-1">4. 什么是 Attention <a class="header-anchor" href="#_4-什么是-attention" aria-label="Permalink to &quot;4. 什么是 Attention&quot;">​</a></h2><p><strong>问题：一句话里，每个词该怎么理解别的词？</strong></p><p>「猫坐在垫子上」 → 「猫」应该多看「坐」、「垫子」。</p><p>Attention 做的事：每个词给其他所有词打分（用点积），然后按分数取信息（加权求和）。</p><p><strong>比喻</strong>：你在一屋子人里找熟人。你扫一圈，给每个人打分，然后把注意力放在分高的人身上。</p><hr><h2 id="_5-什么是梯度下降" tabindex="-1">5. 什么是梯度下降 <a class="header-anchor" href="#_5-什么是梯度下降" aria-label="Permalink to &quot;5. 什么是梯度下降&quot;">​</a></h2><p><strong>问题：怎么找到一个函数的最低点？</strong></p><p>你在山上，闭着眼。每一步感受脚底坡度，往下走。重复到脚下是平的——到谷底了。</p><p>感受坡度 = 求导。往下走 = 更新参数。重复 = 迭代。</p><p><strong>比喻</strong>：闭眼下山。不用知道全貌，走一步看一步，总能到谷底。</p><hr><h2 id="_6-什么是-embedding" tabindex="-1">6. 什么是 Embedding <a class="header-anchor" href="#_6-什么是-embedding" aria-label="Permalink to &quot;6. 什么是 Embedding&quot;">​</a></h2><p><strong>问题：怎么让机器理解文字和图片？</strong></p><p>把任何东西变成一串数字（向量）。相似的文字数字也相似。</p><p>「猫」→ [0.2, 0.8, -0.1]，「狗」→ [0.3, 0.7, -0.2]。这俩向量接近，说明猫和狗语义上相关。</p><p><strong>比喻</strong>：Embedding = 翻译官。把人类世界的一切翻译成机器能比较的数字。</p><hr><h2 id="_7-什么是-token" tabindex="-1">7. 什么是 Token <a class="header-anchor" href="#_7-什么是-token" aria-label="Permalink to &quot;7. 什么是 Token&quot;">​</a></h2><p><strong>问题：LLM 怎么读文字？</strong></p><p>LLM 不认识「你好世界」。它把这四个字切成 Token：<code>[&quot;你&quot;, &quot;好&quot;, &quot;世界&quot;]</code> 或 <code>[&quot;你好&quot;, &quot;世界&quot;]</code>。</p><p>每个 Token 有一个编号，然后查 Embedding 表变成向量。之后才进入 Attention 计算。</p><p><strong>比喻</strong>：Token = 切菜。下锅之前先把食材切成烹饪机认识的形状。</p><hr><h2 id="_8-什么是-rag" tabindex="-1">8. 什么是 RAG <a class="header-anchor" href="#_8-什么是-rag" aria-label="Permalink to &quot;8. 什么是 RAG&quot;">​</a></h2><p><strong>问题：LLM 不知道的事情怎么回答？</strong></p><p>两步：① 先从外部资料库里搜索相关内容 ② 把搜到的内容拼到问题里一起发给 LLM。</p><p>LLM 不需要记住一切，它只需要会「查资料 + 作答」。</p><p><strong>比喻</strong>：开卷考试。不知道答案就翻书，把相关内容抄下来再答题。</p><hr><h2 id="_9-什么是-ai-agent" tabindex="-1">9. 什么是 AI Agent <a class="header-anchor" href="#_9-什么是-ai-agent" aria-label="Permalink to &quot;9. 什么是 AI Agent&quot;">​</a></h2><p><strong>问题：LLM 不只是聊天，还能做事？</strong></p><p>给 LLM 配工具：搜索、计算、查天气、发邮件。LLM 自己决定什么时候用哪个工具。</p><p>循环：LLM 思考 → 调用工具 → 拿到结果 → 继续思考 → 最终回答。</p><p><strong>比喻</strong>：你给实习生一个任务和一套工具。他自己想办法规划、执行、最后给你结果。</p><hr><h2 id="_10-什么是微调-fine-tuning" tabindex="-1">10. 什么是微调（Fine-tuning） <a class="header-anchor" href="#_10-什么是微调-fine-tuning" aria-label="Permalink to &quot;10. 什么是微调（Fine-tuning）&quot;">​</a></h2><p><strong>问题：开源模型怎么变成「你自己的」？</strong></p><p>拿一个训练好的模型（比如 Qwen），用你自己的数据再训练几轮。让模型学会你的语气、你的业务、你的知识。</p><p>不需要从头训，只需要调一小部分参数（LoRA），Colab 免费 GPU 就能跑。</p><p><strong>比喻</strong>：请了一个厨师，再教他做你家常菜。不用重新培养一个厨师。</p><hr><h2 id="🗺️-这些概念怎么拼起来" tabindex="-1">🗺️ 这些概念怎么拼起来 <a class="header-anchor" href="#🗺️-这些概念怎么拼起来" aria-label="Permalink to &quot;🗺️ 这些概念怎么拼起来&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>任何一个词、图片、声音</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>   Embedding（变向量）</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>   Token（分词）</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>   Attention（词和词互看）</span></span>
<span class="line"><span>        ↓  ↓  ↓</span></span>
<span class="line"><span>   LLM          RAG（查资料）</span></span>
<span class="line"><span>        ↓          ↓</span></span>
<span class="line"><span>   Agent（调工具 + 做决策）</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>   Fine-tuning（教模型你自己的东西）</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>   你的 AI 应用</span></span></code></pre></div><hr><blockquote><p>每个概念不超过 3 句话。忘了就翻回来看，不求一次记住。</p></blockquote>`,68)])])}const u=n(o,[["render",p]]);export{g as __pageData,u as default};
